import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const videoMarqueeItems = [
  { id: 1, src: "/assets/videos/cooking.mp4", alt: "Cooking", type: "video" },
  { id: 2, src: "/assets/videos/vid2.mp4", alt: "Vid 2", type: "video" },
  { id: 3, src: "/assets/videos/vid3.mp4", alt: "Vid 3", type: "video" },
  { id: 4, src: "/assets/videos/vid4.mp4", alt: "Vid 4", type: "video" },
  { id: 5, src: "/assets/videos/vid5.mp4", alt: "Vid 5", type: "video" },
  { id: 6, src: "/assets/videos/vid6.mp4", alt: "Vid 6", type: "video" },
];

const placeholderImages = [
  { id: 1, src: "/assets/amb.jpg", alt: "Corridor Ambience", type: "image" },
  { id: 2, src: "/assets/apr.jpg", alt: "Aperitif", type: "image" },
  { id: 3, src: "/assets/ballent.jpg", alt: "Ballentine", type: "image" },
  { id: 4, src: "/assets/bl.jpg", alt: "Bar Lounge", type: "image" },
  { id: 5, src: "/assets/bn.jpg", alt: "Bar Night", type: "image" },
  { id: 6, src: "/assets/dj.jpg", alt: "DJ Night", type: "image" },
  { id: 7, src: "/assets/dri.jpg", alt: "Drinks", type: "image" },
  { id: 8, src: "/assets/f1.jpg", alt: "Food", type: "image" },
  { id: 9, src: "/assets/grp.jpg", alt: "Group Party", type: "image" },
  { id: 10, src: "/assets/nod.jpg", alt: "Night Out", type: "image" },
  { id: 11, src: "/assets/pic.jpg", alt: "Corridor Vibes", type: "image" },
  { id: 12, src: "/assets/piz.jpg", alt: "Pizza", type: "image" },
];

const MovingGallery = () => {
  const renderMedia = (item) => {
    if (item.type === 'video') {
      return (
        <video
          preload="metadata"
          src={item.src}
          alt={item.alt}
          className="w-full h-full object-cover bg-black rounded-lg"
          muted
          autoPlay
          loop
          playsInline
          onLoadedData={() => console.log('Loaded:', item.src)}
        />
      );
    }
    return (
      <img
        src={item.src}
        alt={item.alt}
        className="w-full h-full object-cover grayscale hover:grayscale-0 transition-all duration-500 hover:scale-105 rounded-lg"
        loading="lazy"
      />
    );
  };

  return (
    <section className="py-16 md:py-24 overflow-hidden bg-black">
      <motion.div
        initial={{ opacity: 0, y: 30 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        className="text-center mb-16"
      >
        <span className="font-accent text-gold text-sm tracking-[0.3em] uppercase block mb-4">
          Experience The Vibe
        </span>
        <h2 className="font-heading text-4xl md:text-5xl lg:text-6xl text-white">
          Corridor in Motion
        </h2>
      </motion.div>

      {/* Videos - Portrait Single Pass, No Blur */}
      <div className="mb-12">
        <Marquee speed={25} gradient={false} pauseOnHover>
          {videoMarqueeItems.map((video) => (
            <div key={video.id} className="mx-4 inline-block">
              <div className="w-[200px] h-[350px] md:w-[250px] md:h-[440px] overflow-hidden rounded-2xl shadow-2xl">
                {renderMedia(video)}
              </div>
            </div>
          ))}
        </Marquee>
      </div>

      {/* Images Row 1 LTR */}
      <div className="mb-12">
        <Marquee speed={50} gradient={false} pauseOnHover>
          {placeholderImages.slice(0, 9).map((image) => (
            <div key={image.id} className="mx-4 inline-block">
              <div className="w-[280px] md:w-[360px] h-[180px] md:h-[240px] overflow-hidden rounded-xl">
                {renderMedia(image)}
              </div>
            </div>
          ))}
        </Marquee>
      </div>

      {/* Images Row 2 RTL - 6 images */}
      <div>
        <Marquee speed={50} direction="right" gradient={false} pauseOnHover>
          {placeholderImages.slice(0, 6).map((image) => (
            <div key={`r-${image.id}`} className="mx-4 inline-block">
              <div className="w-[280px] md:w-[360px] h-[180px] md:h-[240px] overflow-hidden rounded-xl">
                {renderMedia(image)}
              </div>
            </div>
          ))}
        </Marquee>
      </div>
    </section>
  );
};

export default MovingGallery;
